import{_ as t,o as a,c as r,a0 as o}from"./chunks/framework.DTwdCQre.js";const h=JSON.parse('{"title":"Runtime Package Map","description":"Package-level map for contributors working on claude-code-Go runtime behavior.","frontmatter":{"title":"Runtime Package Map","description":"Package-level map for contributors working on claude-code-Go runtime behavior."},"headers":[],"relativePath":"architecture/runtime-package-map.md","filePath":"architecture/runtime-package-map.md","lastUpdated":1777485613000}'),n={name:"architecture/runtime-package-map.md"};function d(s,e,i,l,c,p){return a(),r("div",null,[...e[0]||(e[0]=[o(`<h1 id="runtime-package-map" tabindex="-1">Runtime Package Map <a class="header-anchor" href="#runtime-package-map" aria-label="Permalink to &quot;Runtime Package Map&quot;">​</a></h1><p>This page maps product workflows to the Go packages that own them. Use it before changing runtime behavior so fixes land in the right layer.</p><h2 id="runtime-flow" tabindex="-1">Runtime Flow <a class="header-anchor" href="#runtime-flow" aria-label="Permalink to &quot;Runtime Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cmd/go-code</span></span>
<span class="line"><span>  -&gt; config loader</span></span>
<span class="line"><span>  -&gt; provider registry</span></span>
<span class="line"><span>  -&gt; tool registry</span></span>
<span class="line"><span>  -&gt; permission policy</span></span>
<span class="line"><span>  -&gt; agent loop</span></span>
<span class="line"><span>  -&gt; TUI or REPL</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h2 id="package-ownership" tabindex="-1">Package Ownership <a class="header-anchor" href="#package-ownership" aria-label="Permalink to &quot;Package Ownership&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Package</th><th>Responsibility</th><th>Notes</th></tr></thead><tbody><tr><td><code>cmd/go-code</code></td><td>Process entrypoint, flags, setup, runtime wiring.</td><td>Keep orchestration here; avoid embedding business logic in <code>main</code>.</td></tr><tr><td><code>pkg/tui</code></td><td>Default Bubble Tea interactive UI.</td><td>Should delegate slash commands to a shared command layer.</td></tr><tr><td><code>pkg/tty</code></td><td>Legacy line-based REPL.</td><td>Useful reference for command coverage until TUI reaches parity.</td></tr><tr><td><code>internal/agent</code></td><td>Agent loop, history, compaction, recovery, session trace hooks.</td><td>Owns stop-reason dispatch and tool-result feedback.</td></tr><tr><td><code>internal/api</code></td><td>Anthropic request/response types, HTTP client, SSE parsing, API error classification.</td><td>Keep provider-neutral behavior out of this package when possible.</td></tr><tr><td><code>internal/provider</code></td><td>Provider interface and provider adapters.</td><td>Anthropic and OpenAI-compatible differences belong here.</td></tr><tr><td><code>internal/config</code></td><td>Configuration loading and defaults.</td><td>Should expose config source details for doctor output.</td></tr><tr><td><code>internal/tool</code></td><td>Tool interface, registry, and built-in tool registration.</td><td>Tool definitions must stay concise and schema-valid.</td></tr><tr><td><code>internal/tool/builtin</code></td><td>Built-in local tools such as read, edit, bash, tree, diff, web fetch, todo, notebook.</td><td>Side effects must be permission-gated by the caller.</td></tr><tr><td><code>internal/permission</code></td><td>Permission policy, rules, prompter, file boundaries, bash semantic checks.</td><td>This package decides; agent/tool layers must enforce.</td></tr><tr><td><code>internal/session</code></td><td>JSONL session persistence and trace line helpers.</td><td>Needs a normalized schema for replay and debugging.</td></tr><tr><td><code>internal/hooks</code></td><td>Pre/post tool execution hooks.</td><td>Pre-hook failures should block execution.</td></tr><tr><td><code>internal/skills</code></td><td>User-defined reusable prompts/workflows.</td><td>Invalid skill files should not break startup.</td></tr><tr><td><code>internal/tool/mcp</code></td><td>MCP client, transport, and adapter.</td><td>MCP tools must enter the same registry and permission flow.</td></tr><tr><td><code>internal/lsp</code></td><td>LSP client features.</td><td>Optional surface; should fail closed when no server is configured.</td></tr><tr><td><code>internal/update</code></td><td>Release checking and binary update.</td><td>User-triggered network behavior only.</td></tr><tr><td><code>internal/cost</code></td><td>Token and cost tracking helpers.</td><td>Provider pricing assumptions must be documented.</td></tr><tr><td><code>internal/telemetry</code></td><td>Optional local telemetry primitives.</td><td>Keep disabled until product/privacy story is explicit.</td></tr></tbody></table><h2 id="contributor-rules" tabindex="-1">Contributor Rules <a class="header-anchor" href="#contributor-rules" aria-label="Permalink to &quot;Contributor Rules&quot;">​</a></h2><ul><li>UI packages should not duplicate command semantics.</li><li>Tool implementations should perform local validation, but permission approval belongs above tool execution.</li><li>Provider adapters should normalize errors before they reach UI code.</li><li>Tests that require sockets, home-directory writes, or built binaries must document those requirements.</li><li>Public docs should only claim workflows that are verified by tests or listed in <code>PARITY.md</code>.</li></ul>`,8)])])}const m=t(n,[["render",d]]);export{h as __pageData,m as default};
